import 'dart:convert';
import 'package:flutter_test/flutter_test.dart';
import 'package:pinepods_mobile/services/security/certificate_manager.dart';

// Throwaway self-signed cert (CN=test) + PKCS#12 (password: testpass),
// generated only for this test.
const _certPem = '';
const _clientP12 = '';

void main() {
  final ca = base64Decode(_certPem);
  final p12 = base64Decode(_clientP12);

  test('validateServerCa accepts a real PEM certificate', () {
    expect(CertificateManager.validateServerCa(ca), isNull);
  });

  test('validateServerCa rejects garbage', () {
    expect(CertificateManager.validateServerCa(utf8.encode('not a cert')), isNotNull);
  });

  test('validateClientCert accepts p12 with correct password', () {
    expect(CertificateManager.validateClientCert(p12, 'testpass'), isNull);
  });

  test('validateClientCert reports a password error on wrong password', () {
    final err = CertificateManager.validateClientCert(p12, 'wrongpass');
    expect(err, isNotNull);
    expect(err!.toLowerCase(), contains('password'));
  });
}
